    HWREGH(base + EPWM_O_ETINTPS) =
         ((HWREGH(base + EPWM_O_ETINTPS) & ~EPWM_ETINTPS_INTPRD2_M) |
           eventCount);
}

{
    //
    // Check the arguments
    //
    ASSERT(EPWM_isBaseValid(base));

