    // Return INT bit of ETFLG register
    //
    return(((HWREGH(base + EPWM_O_ETFLG) & 0x1U) == 0x1U) ? true : false);
}

{
    //
    // Check the arguments
    //
    ASSERT(EPWM_isBaseValid(base));

